WHERE q.status = 1

    AND q.question_type = #{query.questionType}


    AND q.difficulty = #{query.difficulty}


    AND q.knowledge_point LIKE CONCAT('%', #{query.knowledgePoint}, '%')


    AND q.title LIKE CONCAT('%', #{query.keyword}, '%')

